#include <stdio.h>
#include <math.h>

int gcd_int(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        int g = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (i == 0) g = x; else g = gcd_int(g, x);
        }
        if (g == 1) {
            printf("-1\n");
            continue;
        }
        int ans = g;
        for (int d = 2; d * d <= g; ++d) {
            if (g % d == 0) { ans = d; break; }
        }
        printf("%d\n", ans);
    }
    return 0;
}

