import sys, math

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        g = 0
        for i in range(N):
            x = int(next(it))
            if i == 0:
                g = x
            else:
                g = math.gcd(g, x)
        if g == 1:
            out_lines.append('-1')
            continue
        ans = g
        limit = int(math.isqrt(g))
        for d in range(2, limit + 1):
            if g % d == 0:
                ans = d
                break
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

